import struct, zlib, io
def _png(r,g,b):
    def chunk(t,d): c=zlib.crc32(t+d)&0xFFFFFFFF; return struct.pack('>I',len(d))+t+d+struct.pack('>I',c)
    ihdr=struct.pack('>IIBBBBB',8,8,8,2,0,0,0); raw=b'\x00'+bytes([r,g,b]*8)*8; idat=zlib.compress(raw)
    return b'\x89PNG\r\n\x1a\n'+chunk(b'IHDR',ihdr)+chunk(b'IDAT',idat)+chunk(b'IEND',b'')
open('/tmp/eval01_image.png','wb').write(_png(255,0,0))

